const closes = ctx.underlying.klines.map((k) => k.close);
const rsi14 = ctx.helpers.rsi(closes, 14);
const emaFast = ctx.helpers.emaArray(closes, 12).at(-1);
const emaSlow = ctx.helpers.emaArray(closes, 26).at(-1);
const momentum = Math.sign(emaFast - emaSlow);
let volR = 1;
try { volR = ctx.helpers.volRatio(ctx, '1h', '24h'); } catch {}

const logit   = (p) => Math.log(p / (1 - p));
const sigmoid  = (x) => 1 / (1 + Math.exp(-x));
const clamp    = (p) => Math.min(Math.max(p, 1e-6), 1 - 1e-6);

const THRESHOLD = 0.04;
const rsiShift      = (rsi14 - 50) / 200;
const momentumShift = momentum * 0.04;
const volShift      = (volR - 1) * 0.02;
const totalShift    = rsiShift + momentumShift + volShift;

return ctx.markets.map((market) => {
  const base = { question: market.question, questionType: market.questionType, expiryDate: market.expiryDate };
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { ...base, decision: 'hold', reason: 'closed or expired' };
    }
    const mCtx = { market, underlying: ctx.underlying, timing: ctx.timing };
    let probs;
    if (market.questionType === 'firstHit') {
      probs = ctx.helpers.firstHitProbabilities(mCtx, { seed: 42 });
    } else {
      let yes0;
      if (market.questionType === 'hit') {
        yes0 = ctx.helpers.bsOneTouch(mCtx);
      } else if (market.questionType === 'above') {
        yes0 = ctx.helpers.bsAbove(mCtx);
      } else if (market.questionType === 'below') {
        yes0 = 1 - ctx.helpers.bsAbove(mCtx);
      } else if (market.questionType === 'range') {
        yes0 = ctx.helpers.bsRange(mCtx);
      } else if (market.questionType === 'directional') {
        yes0 = 0.5;
      } else {
        return { ...base, decision: 'hold', reason: 'unsupported questionType: ' + market.questionType };
      }
      const yesAdj = sigmoid(logit(clamp(yes0)) + totalShift);
      probs = ctx.helpers.binaryProbsFromYesProb(mCtx, yesAdj);
    }
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];
    if (best.edge < THRESHOLD) {
      return { ...base, decision: 'hold', edge: best.edge, fairPrice: edges[0].fairPrice, marketPrice: edges[0].marketPrice };
    }
    return { ...base, decision: 'buy', side: best.label, fairPrice: best.fairPrice, marketPrice: best.marketPrice, edge: best.edge };
  } catch (err) {
    return { ...base, decision: 'hold', reason: String(err) };
  }
});
